import React from "react";

export default function WeatherOverlay({ weather, isDay }) {
  let gifFilename = "";

  const condition = weather.toLowerCase();

  if (condition.includes("thunderstorm")) {
    gifFilename = "thunderstorm.gif";
  } else if (condition.includes("snow")) {
    gifFilename = "snow.gif";
  } else if (condition.includes("rain") || condition.includes("drizzle")) {
    gifFilename = isDay ? "rain.gif" : "rainNight.gif";
  } else if (condition.includes("wind")) {
    gifFilename = "Windy-Weather-App.gif";
  } else if (condition.includes("cloud")) {
    if (condition.includes("partly") && isDay) gifFilename = "PCday.gif";
    else if (condition.includes("partly") && !isDay) gifFilename = "PCnight.gif";
    else gifFilename = "cloudy.gif";
  } else if (condition.includes("clear")) {
    gifFilename = isDay ? "Sun-Weather-App.gif" : "night.gif";
  } else {
    gifFilename = isDay ? "noon.gif" : "PCdawn.gif";
  }

  const gifPath = `/overlays/${gifFilename}`;

  return (
    <div className="absolute inset-0 -z-10 overflow-hidden">
      <img
        src={gifPath}
        alt="Weather Overlay"
        className="w-full h-full object-cover opacity-60"
      />
    </div>
  );
}
